  })),
);
const TrustedPartners = lazy(() =>
  import("./TrustedPartners").then((module) => ({
    default: module.TrustedPartners,
  })),
);
const PartnerOpportunities = lazy(() =>
  import("./PartnerOpportunities").then((module) => ({
    default: module.PartnerOpportunities,
  })),
);
const ContactForm = lazy(() =>
  import("./ContactForm").then((module) => ({
    default: module.ContactForm,
  })),
);
const PageFooter = lazy(() =>
  import("./PageFooter").then((module) => ({
    default: module.PageFooter,
  })),
);

const DEFERRED_SECTION_ROOT_MARGIN = "600px 0px 600px 0px";

export function DeferredPageSections() {
  const sentinelRef = useRef<HTMLDivElement>(null);
  const [shouldRender, setShouldRender] = useState(false);

  useEffect(() => {
    const sentinel = sentinelRef.current;
    if (!sentinel || shouldRender) {
      return undefined;
    }

    const observer = new IntersectionObserver(
      ([entry]) => {
        if (entry?.isIntersecting) {
          setShouldRender(true);
          observer.disconnect();
        }
      },
      { rootMargin: DEFERRED_SECTION_ROOT_MARGIN },
    );

    observer.observe(sentinel);

    return () => observer.disconnect();
  }, [shouldRender]);

  return (
    <>
      <div
        ref={sentinelRef}
        className="deferred-sections-sentinel"
        aria-hidden="true"
      />
      {shouldRender ? (
        <div className="deferred-sections">
          <Suspense fallback={null}>
            {/*    <FactDrivenScale /> */}
            {/*  <LeadingPositions /> */}
            {/*   <ParticipantsGrowth /> */}
            <div className="section-container">

              <OurProjects />
              <MediaMetrics />
              <Geography />
              <TrustedPartners />

              <PartnerOpportunities />
              {/*      <EffectivenessMetrics /> */}
              <ContactForm />
            </div>
            <PageFooter />
          </Suspense>
        </div>
      ) : null}
    </>
  );
}

