/* ===== About Section ===== */
.about-section {
  background: #ffffff;
  color: #1e1e1e;
  width: min(100%, 1920px);
  margin-inline: auto;
  overflow: hidden;
}

.about-inner {
  display: flex;
  flex-direction: column;
  gap: 24px;
}

/* ===== Левая колонка — контент ===== */
.about-content {
  padding: 20px;
  display: flex;
  flex-direction: column;
  gap: 20px;
}

.about-title {
  margin: 0;
  font-family: "Druk Cyr", sans-serif;
  font-size: clamp(32px, 8vw, 80px);
  font-weight: 500;
  letter-spacing: 0.01em;
  color: #1e1e1e;
  line-height: 0.95;
  text-transform: uppercase;
  max-width: 404px;
}

.about-description {
  margin: 0;
  font-family: Inter, Arial, sans-serif;
  font-size: clamp(16px, 4.2vw, 18px);
  font-weight: 400;
  line-height: 1.15;
  color: #1e1e1e;
  max-width: 448px;
}

/* ===== Блок метрик ===== */
.about-metrics {
  display: flex;
  flex-direction: column;
  gap: 48px;
  max-width: 488px;
}

.about-metric {
  display: flex;
  flex-direction: column;
  gap: 4px;
}

.about-metric-value {
  font-family: "Druk Cyr", sans-serif;
  font-size: clamp(36px, 10vw, 148px);
  font-weight: 500;
  letter-spacing: 0.01em;
  color: #4cf2a3;
  line-height: 0.95;
}

.about-metric-label {
  font-family: Inter, Arial, sans-serif;
  font-size: clamp(12px, 3.5vw, 16px);
  font-weight: 400;
  line-height: 1.15;
  color: #1e1e1e;
}

/* ===== Правая колонка — изображение ===== */
.about-image-wrapper {
  position: relative;
  width: 100%;
  aspect-ratio: 761 / 690;
}

.about-image {
  width: 100%;
  height: 100%;
  object-fit: cover;
  border-radius: 24px;
  display: block;
}

/* Декоративные эллипсы */
.about-dot {
  position: absolute;
  width: 16px;
  height: 16px;
  border-radius: 999px;
  background: #ffffff;
  z-index: 1;
}

.about-dot--1 {
  top: 12px;
  left: 12px;
}

.about-dot--2 {
  top: 50px;
  left: 12px;
}

.about-dot--3 {
  bottom: 50px;
  left: 12px;
}

.about-dot--4 {
  bottom: 12px;
  left: 12px;
}

/* ===== Desktop (768px+) ===== */
@media (min-width: 768px) {
  .about-inner {
    flex-direction: row;
    gap: 0;
    align-items: flex-start;
  }

  .about-content {
    padding: 74px 0 0 47px;
    flex: 1;
    max-width: 604px;
  }

  .about-title {
    font-size: 80px;
    max-width: 404px;
  }

  .about-description {
    font-size: 18px;
    max-width: 448px;
  }

  .about-metrics {
    max-width: 488px;
    gap: 121px;
  }

  /* Первая строка метрик — две карточки в ряд */
  .about-metric:first-child {
    width: 136px;
  }

  .about-metric:nth-child(2) {
    width: 265px;
  }

  .about-metric-value {
    font-size: 148px;
  }

  .about-metric-label {
    font-size: 16px;
  }

  /* Широкие метрики */
  .about-metric--wide {
    max-width: 434px;
  }

  .about-metric--wide:last-child {
    max-width: 429px;
  }

  /* Правая колонка — изображение */
  .about-image-wrapper {
    width: 761px;
    height: 690px;
    flex-shrink: 0;
  }

  .about-dot--1 {
    top: 20px;
    left: 20px;
  }

  .about-dot--2 {
    top: 50px;
    left: 20px;
  }

  .about-dot--3 {
    bottom: 50px;
    left: 20px;
  }

  .about-dot--4 {
    bottom: 20px;
    left: 20px;
  }
}

/* ===== Tablet (1120px+) ===== */
@media (min-width: 1120px) {
  .about-inner {
    gap: 48px;
  }
}

/* ===== Large Desktop (1440px+) ===== */
@media (min-width: 1440px) {
  .about-inner {
    max-width: 1440px;
    margin-inline: auto;
  }
}

